import anthropic
from tenacity import (
    retry,
    retry_if_exception_type,
    stop_after_attempt,
    wait_random_exponential,
)

client = anthropic.Anthropic()


@retry(
    retry=retry_if_exception_type(anthropic.RateLimitError),
    wait=wait_random_exponential(multiplier=1, max=60),
    stop=stop_after_attempt(6),
)
def chat(prompt: str) -> str:
    return client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        messages=[{"role": "user", "content": prompt}],
    ).content[0].text


print(chat("What is the capital of Japan?"))

import anthropic
import itertools
import threading
import time
from dataclasses import dataclass, field


@dataclass
class KeySlot:
    key: str
    blocked_until: float = 0.0
    _lock: threading.Lock = field(default_factory=threading.Lock, repr=False)

    def is_available(self) -> bool:
        return time.monotonic() >= self.blocked_until

    def block(self, seconds: float) -> None:
        with self._lock:
            self.blocked_until = time.monotonic() + seconds


class KeyPool:
    def __init__(self, keys: list[str]):
        self._slots = [KeySlot(k) for k in keys]
        self._cycle = itertools.cycle(self._slots)
        self._pool_lock = threading.Lock()

    def next_available(self, timeout: float = 60.0) -> KeySlot:
        deadline = time.monotonic() + timeout
        while time.monotonic() < deadline:
            with self._pool_lock:
                for _ in range(len(self._slots)):
                    slot = next(self._cycle)
                    if slot.is_available():
                        return slot
            time.sleep(0.5)
        raise RuntimeError("All API keys are rate-limited")

    def call(self, prompt: str) -> str:
        slot = self.next_available()
        try:
            client = anthropic.Anthropic(api_key=slot.key)
            resp = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=256,
                messages=[{"role": "user", "content": prompt}],
            )
            return resp.content[0].text
        except anthropic.RateLimitError:
            slot.block(seconds=60)
            raise


